class Solution(object):
    def minValidStrings(self, words, target):
        """
        :type words: List[str]
        :type target: str
        :rtype: int
        """
        # Build Trie of all prefixes
        class TrieNode:
            def __init__(self):
                self.children = {}
                self.is_prefix = False

        root = TrieNode()

        # Insert all prefixes of all words
        for word in words:
            node = root
            for char in word:
                if char not in node.children:
                    node.children[char] = TrieNode()
                node = node.children[char]
                node.is_prefix = True

        # DP: dp[i] = minimum strings needed to form target[0:i]
        n = len(target)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(n):
            if dp[i] == float('inf'):
                continue

            # Try to extend from position i
            node = root
            for j in range(i, n):
                char = target[j]
                if char not in node.children:
                    break  # Can't extend further

                node = node.children[char]
                # After adding character at position j, we've matched target[i:j+1]
                # This is a valid prefix of some word
                dp[j + 1] = min(dp[j + 1], dp[i] + 1)

        return dp[n] if dp[n] != float('inf') else -1
